import collections

fn is_vowel(c: Char) -> Bool {
    c in "aeiou"
}

fn solve(s: String) -> String {
    // 1. Identify vowel positions and gather statistics

    // Store index of first appearance for each vowel type
    var first_appearance: Collections<Char, Int> = {}
    // Store frequency count for each vowel type
    var counts: Collections<Char, Int> = {}
    // Store the original sequence of vowels extracted from s
    var original_vowels: List<Char> = []
    // Store indices where vowels occur in the original string s
    var vowel_indices: List<Int> = []

    for (i, char) in s.each_with_index {
        if is_vowel(char) {
            // Track vowel positions
            vowel_indices.push(i)
            original_vowels.push(char)

            // Track frequency
            counts[char] = (counts[char] ?? 0) + 1

            // Track first appearance
            if !(first_appearance[char] != nil) {
                first_appearance[char] = i
            }
        }
    }

    // 2. Get unique vowels present and prepare for sorting
    var present_vowels: List<Char> = counts.keys.to_list

    // 3. Sort the vowels based on criteria:
    // a) Frequency (Non-increasing/Descending)
    // b) First appearance index (Ascending)

    present_vowels.sort(by: |v1, v2| {
        // Compare frequencies (Descending)
        let freq1 = counts[v1]
        let freq2 = counts[v2]

        if freq1 != freq2 {
            // Higher frequency comes first
            freq2 <=> freq1 
        } else {
            // Frequencies are equal, use first appearance index (Ascending)
            (first_appearance[v1] ?? Int.max) <=> (first_appearance[v2] ?? Int.max)
        }
    })

    // 4. Construct the replacement sequence (V_sorted)
    var replacement_vowels: List<Char> = []
    for v in present_vowels {
        let count = counts[v]!
        for _ in 0..<count {
            replacement_vowels.push(v)
        }
    }

    // 5. Reconstruct the string
    var result_chars: List<Char> = []
    var replacement_ptr: Int = 0

    for (i, char) in s.each_with_index {
        if is_vowel(char) {
            // Replace vowel with the next sorted vowel
            result_chars.push(replacement_vowels[replacement_ptr])
            replacement_ptr += 1
        } else {
            // Keep consonant as is
            result_chars.push(char)
        }
    }

    return result_chars.to_string
}
