const VOWELS = new Set(['a', 'e', 'i', 'o', 'u']);

function solve(s) {
    const n = s.length;

    // 1. Calculate frequencies and first appearance indices
    const counts = new Map();
    const firstIndex = new Map();

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (VOWELS.has(char)) {
            // Update count
            counts.set(char, (counts.get(char) || 0) + 1);

            // Record first index if not already recorded
            if (!firstIndex.has(char)) {
                firstIndex.set(char, i);
            }
        }
    }

    // 2. Collect unique vowels present and prepare for sorting
    let uniqueVowels = Array.from(counts.keys());

    // 3. Sort the unique vowels based on criteria
    // Primary: Frequency (descending)
    // Secondary: First appearance index (ascending)
    uniqueVowels.sort((v1, v2) => {
        const count1 = counts.get(v1);
        const count2 = counts.get(v2);

        // Compare frequencies (descending)
        if (count1 !== count2) {
            return count2 - count1;
        }

        // Frequencies are equal, compare first index (ascending)
        const index1 = firstIndex.get(v1);
        const index2 = firstIndex.get(v2);
        return index1 - index2;
    });

    // 4. Build the final sorted sequence of vowels
    const sortedVowelSequence = [];
    for (const vowel of uniqueVowels) {
        const count = counts.get(vowel);
        for (let i = 0; i < count; i++) {
            sortedVowelSequence.push(vowel);
        }
    }

    // 5. Reconstruct the string
    let result = Array(n);
    let vowelSequenceIndex = 0;

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (VOWELS.has(char)) {
            // Replace the vowel at this position with the next vowel from the sorted sequence
            result[i] = sortedVowelSequence[vowelSequenceIndex];
            vowelSequenceIndex++;
        } else {
            // Consonants remain unchanged
            result[i] = char;
        }
    }

    return result.join('');
}
