import core

fn is_vowel(c: Char): Bool {
	c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u'
}

fn solve(s: String): String {
	let vowels = "aeiou"
	let counts = Hash(String, Int)
	let first_occurrence = Hash(String, Int)

	// 1. Calculate frequencies and first occurrences
	for (i, char) in s.split(Char) {
		if is_vowel(char) {
			// Count frequency
			let count = counts[char] + 1
			counts[char] = count

			// Record first occurrence if not set
			if !first_occurrence.key?(char) {
				first_occurrence[char] = i
			}
		}
	}

	// 2. Collect unique vowels present
	let unique_vowels = counts.keys.map { |v| v }

	// 3. Sort the unique vowels based on criteria
	// Criteria: Frequency DESC, First Appearance ASC
	let sorted_vowels = unique_vowels.sort { |v1, v2|
		let freq1 = counts[v1]
		let freq2 = counts[v2]

		// Primary sort: Frequency descending
		if freq1 != freq2 {
			return freq2 <=> freq1 // Descending comparison (b <=> a)
		}

		// Secondary sort: First appearance ascending
		let idx1 = first_occurrence[v1]
		let idx2 = first_occurrence[v2]
		return idx1 <=> idx2 // Ascending comparison
	}

	// 4. Construct the final vowel sequence string
	var vowel_sequence_chars: [Char] = []
	for (vowel_type in sorted_vowels) {
		let count = counts[vowel_type]
		for _ in 0..<count {
			vowel_sequence_chars.push(vowel_type[0])
		}
	}

	let vowel_sequence = vowel_sequence_chars

	// 5. Reconstruct the string
	var result_chars: [Char] = []
	var vowel_seq_idx: Int = 0

	for (char in s.split(Char)) {
		if is_vowel(char) {
			// Replace vowel with the next character from the sorted sequence
			result_chars.push(vowel_sequence[vowel_seq_idx])
			vowel_seq_idx += 1
		} else {
			// Keep consonants as they are
			result_chars.push(char)
		}
	}

	return String(result_chars)
}
